function ensureEmbeddedBuildAssets(repoRoot) {
  const assetRoot = path.join(repoRoot, EMBEDDED_BUILD_ASSET_DIR);
  fs.mkdirSync(assetRoot, { recursive: true });

  for (const [relativePath, base64Content] of Object.entries(EMBEDDED_BUILD_ASSETS)) {
    const absolutePath = path.join(assetRoot, relativePath);
    fs.mkdirSync(path.dirname(absolutePath), { recursive: true });

    const nextBuffer = Buffer.from(base64Content, "base64");
    if (fs.existsSync(absolutePath)) {
      const currentBuffer = fs.readFileSync(absolutePath);
      if (currentBuffer.length === nextBuffer.length && currentBuffer.equals(nextBuffer)) {
        continue;
      }
    }
    fs.writeFileSync(absolutePath, nextBuffer);
  }

  return assetRoot;
}

function toPosix(value) {
  return value.split(path.sep).join("/");
}

function readText(filePath) {
  return fs.readFileSync(filePath, "utf8");
}

function writeText(filePath, content) {
  fs.writeFileSync(filePath, content, "utf8");
}

function detectEol(text) {
  return text.includes("\r\n") ? "\r\n" : "\n";
}

function insertAfter(text, marker, toInsert) {
  const markerIndex = text.indexOf(marker);
  if (markerIndex < 0) {
    throw new Error(`Patch anchor not found: "${marker}"`);
  }

  const insertIndex = markerIndex + marker.length;
  return `${text.slice(0, insertIndex)}${toInsert}${text.slice(insertIndex)}`;
}

function replaceLiteral(text, from, to) {
  if (text.includes(to)) {
    return text;
  }
  if (!text.includes(from)) {
    return text;
  }
  return text.replace(from, to);
}

function joinFortranStatements(text) {
  const statements = [];
  let current = "";

  for (const rawLine of text.split(/\r?\n/)) {
    const noComment = rawLine.split("!")[0] || "";
    if (!noComment.trim()) {
      continue;
    }

    let line = noComment;
    if (current) {
      line = line.replace(/^\s*&\s*/, "");
    }

    const hasContinuation = /&\s*$/.test(line);
    line = line.replace(/&\s*$/, "").trim();
    if (!line) {
      continue;
    }

    current = current ? `${current} ${line}` : line;
    if (!hasContinuation) {
      statements.push(current.trim());
      current = "";
    }
  }

  if (current.trim()) {
    statements.push(current.trim());
  }

  return statements;
}

function splitTopLevelCsv(value) {
  const parts = [];
  let depth = 0;
  let token = "";

  for (const ch of value) {
    if (ch === "(") {
      depth += 1;
      token += ch;
      continue;
    }

    if (ch === ")") {
      depth = Math.max(0, depth - 1);
      token += ch;
      continue;
    }

    if (ch === "," && depth === 0) {
      if (token.trim()) {
        parts.push(token.trim());
      }
      token = "";
      continue;
    }

    token += ch;
  }

  if (token.trim()) {
    parts.push(token.trim());
  }

  return parts;
}

function parseCharacterLen(typePrefix) {
  const match = typePrefix.match(/CHARACTER\s*\(\s*([^)]+)\s*\)/i);
  if (!match) {
    return null;
  }

  let raw = match[1].replace(/\s+/g, "");
  if (/^LEN=/i.test(raw)) {
    raw = raw.replace(/^LEN=/i, "");
  }
  if (raw.includes("*")) {
    raw = raw.split("*")[0];
  }

  const parsed = Number.parseInt(raw, 10);
  if (Number.isFinite(parsed) && parsed > 0) {
    return parsed;
  }

  return null;
}

function parseModelStufAllocatables(modelStufText) {
  const statements = joinFortranStatements(modelStufText);
  const byName = new Map();

  for (const statement of statements) {
    if (!/ALLOCATABLE/i.test(statement) || !statement.includes("::")) {
      continue;
    }

    const parts = statement.split("::");
    if (parts.length < 2) {
      continue;
    }

    const typePrefix = parts[0];
    const declarations = parts.slice(1).join("::");
    let kind = null;
    let charLen = null;

    if (/^\s*INTEGER\s*\(/i.test(typePrefix)) {
      kind = "int";
    } else if (/^\s*REAL\s*\(/i.test(typePrefix)) {
      kind = "real";
    } else if (/^\s*CHARACTER\b/i.test(typePrefix)) {
      kind = "char";
      charLen = parseCharacterLen(typePrefix);
      if (charLen === null) {
        continue;
      }
    } else {
      continue;
    }

    const variables = splitTopLevelCsv(declarations);
    for (const variable of variables) {
      const match = variable.match(/^([A-Za-z_][A-Za-z0-9_]*)\s*(\(([^)]*)\))?/);
      if (!match) {
        continue;
      }

      const name = match[1].toLowerCase();
      const dims = match[3];
      if (!dims) {
        continue;
      }

      const rank = splitTopLevelCsv(dims).length;
      if (rank < 1) {
        continue;
      }

      byName.set(name, {
        name,
        kind,
        rank,
        charLen
      });
    }
  }

  return Array.from(byName.values());
}

function renderDescriptorInit(entry) {
  const symbol = "_QMmodel_stufE" + entry.name;
  const descPtr = "((unsigned char *)" + symbol + ")";
  const elementBytes = entry.kind === "real" ? 8 : entry.kind === "int" ? 4 : entry.charLen;
  const typeCode = entry.kind === "real" ? 28 : entry.kind === "int" ? 9 : 40;
  const lines = [
    "  {",
    "    unsigned char *desc = " + descPtr + ";",
    "    const uint64_t elemBytes = " + elementBytes + "u;",
    "    web_desc_store_u64(desc + 8, elemBytes);",
    "    web_desc_store_u32(desc + 16, 20240719u);",
    "    desc[20] = (unsigned char)" + entry.rank + ";",
    "    desc[21] = (unsigned char)" + typeCode + ";",
    "    desc[22] = (unsigned char)2;",
    "    desc[23] = 0;"
  ];

  for (let dim = 0; dim < entry.rank; dim += 1) {
    const dimOffset = 24 + dim * 24;
    const strideExpr = dim === 0 ? "elemBytes" : "0u";
    lines.push("    web_desc_store_u64(desc + " + dimOffset + ", 1u);");
    lines.push("    web_desc_store_u64(desc + " + (dimOffset + 8) + ", 0u);");
    lines.push("    web_desc_store_u64(desc + " + (dimOffset + 16) + ", " + strideExpr + ");");
  }

  lines.push("  }");
  return lines;
}

function generateWebDescriptorFix(entries) {
  const entryCount = Array.isArray(entries) ? entries.length : 0;
  const lines = [];
  lines.push("/* Auto-generated by tools/build.js. */");
  lines.push("/* Descriptor mutation is intentionally disabled. */");
  lines.push("");
  lines.push("void web_dump_grid_rgrid_descriptors(void) {");
  lines.push("}");
  lines.push("");
  lines.push("void web_fix_model_stuf_descriptors(void) {");
  lines.push("  (void)" + entryCount + ";");
  lines.push("}");
  lines.push("");
  return lines.join("\n");
}

function parseNameSetFromEnv(envName) {
  const raw = process.env[envName];
  if (!raw) {
    return null;
  }

  const values = raw
    .split(",")
    .map((token) => token.trim().toLowerCase())
    .filter((token) => token.length > 0);

  return new Set(values);
}

function selectDescriptorEntries(parsedEntries) {
  const mode = (process.env.WEBMYSTRAN_DESCRIPTOR_MODE || "all").trim().toLowerCase();
  let entries = parsedEntries.slice();

  if (mode === "none") {
    entries = [];
  } else if (mode === "numeric") {
    entries = entries.filter((entry) => entry.kind !== "char");
  } else if (mode === "int" || mode === "real" || mode === "char") {
    entries = entries.filter((entry) => entry.kind === mode);
  } else if (mode !== "all") {
    throw new Error(
      `Invalid WEBMYSTRAN_DESCRIPTOR_MODE="${mode}". Supported values: none, all, numeric, int, real, char.`
    );
  }

  const allowlist = parseNameSetFromEnv("WEBMYSTRAN_DESCRIPTOR_ALLOWLIST");
  if (allowlist && allowlist.size > 0) {
    entries = entries.filter((entry) => allowlist.has(entry.name));
  }

  const denylist = parseNameSetFromEnv("WEBMYSTRAN_DESCRIPTOR_DENYLIST");
  if (denylist && denylist.size > 0) {
    entries = entries.filter((entry) => !denylist.has(entry.name));
  }

  console.log(
    `descriptor filter mode=${mode}, allowlist=${allowlist ? allowlist.size : 0}, denylist=${denylist ? denylist.size : 0}, selected=${entries.length}`
  );

  return entries;
}

function generateDescriptorFixSource(repoRoot) {
  const modelStufPath = path.join("sources", "MYSTRAN", "Source", "Modules", "MODEL_STUF.f90");
  const descriptorPath = path.join("sources", "MYSTRAN", "Source", "UTIL", "web_descriptor_fix.c");
  const modelStufAbs = path.join(repoRoot, modelStufPath);
  const descriptorAbs = path.join(repoRoot, descriptorPath);

  if (!fs.existsSync(modelStufAbs)) {
    throw new Error(`MODEL_STUF not found: ${toPosix(modelStufAbs)}`);
  }

  const modelStufText = readText(modelStufAbs);
  const parsedEntries = parseModelStufAllocatables(modelStufText);
  const byName = new Map(parsedEntries.map((entry) => [entry.name, entry]));
  const supplementalEntries = [
    { name: "title", kind: "char", rank: 1, charLen: 256 },
    { name: "stitle", kind: "char", rank: 1, charLen: 256 },
    { name: "label", kind: "char", rank: 1, charLen: 256 }
  ];
  for (const entry of supplementalEntries) {
    if (!byName.has(entry.name)) {
      parsedEntries.push(entry);
    }
  }
  const entries = selectDescriptorEntries(parsedEntries);

  const generated = generateWebDescriptorFix(entries);
  const current = fs.existsSync(descriptorAbs) ? readText(descriptorAbs) : "";

  if (current !== generated) {
    writeText(descriptorAbs, generated);
    console.log(`generated ${toPosix(descriptorPath)} (${entries.length} descriptor(s))`);
  } else {
    console.log(`ok ${toPosix(descriptorPath)} (${entries.length} descriptor(s))`);
  }
}

