          "READ(SCR(1),*,IOSTAT=$1) SETID,AGRID,ACID_G,FORMON(1),FORMON(2),FORMON(3),FORMOM_KIND\n            IF      (FORMOM_KIND == 1) THEN\n               NAME = 'FORCE   '\n            ELSE IF (FORMOM_KIND == 2) THEN\n               NAME = 'MOMENT  '\n            ELSE\n               NAME = 'UNKNOWN '\n            ENDIF"
